// PII scrubbing pre-LLM (defesa em profundidade)
const item = $input.item.json;
const raw = (item.body && item.body.message && item.body.message.text) || '';
const sender = (item.body && item.body.sender) || 'unknown';

const patterns = {
  cpf: /\b\d{3}\.?\d{3}\.?\d{3}-?\d{2}\b/g,
  rg: /\b\d{1,2}\.?\d{3}\.?\d{3}-?\d{1}\b/g,
  phone: /\b\(\d{2}\)\s?9?\d{4}-?\d{4}\b/g,
  email: /\b[\w.-]+@[\w.-]+\.\w+\b/g
};

let scrubbed = raw;
let findings = [];
let redactionCount = 0;

for (const [type, pattern] of Object.entries(patterns)) {
  const matches = scrubbed.match(pattern);
  if (matches) {
    findings.push({ type, count: matches.length });
    redactionCount += matches.length;
    scrubbed = scrubbed.replace(pattern, `[${type.toUpperCase()}_REDACTED]`);
  }
}

// Detectar tipo de emolumento baseado em keywords
const lower = scrubbed.toLowerCase();
let tipo = 'certidao_casamento'; // default conservador
if (/casament/.test(lower)) tipo = 'certidao_casamento';
else if (/negativa/.test(lower)) tipo = 'certidao_negativa';
else if (/positiva/.test(lower)) tipo = 'certidao_positiva';
else if (/certid/.test(lower)) tipo = 'certidao_casamento';
else if (/compra.{0,3}venda|escritura.{0,3}compra/.test(lower)) tipo = 'escritura_compra_venda';
else if (/doaç|doacao/.test(lower)) tipo = 'escritura_doacao';
else if (/escritur/.test(lower)) tipo = 'escritura_compra_venda';
else if (/procur/.test(lower)) tipo = 'procuracao';
else if (/reconhec|firm/.test(lower)) tipo = 'reconhecimento_firma';
else if (/autent/.test(lower)) tipo = 'autenticacao';
else if (/nasc/.test(lower)) tipo = 'registro_nascimento';
else if (/óbito|obito/.test(lower)) tipo = 'registro_obito';

return { json: { sender, raw, scrubbed, findings, redactionCount, tipo } };

